class Solution {
public:
    string licenseKeyFormatting(string s, int k) {
        string res;
        int count = 0;
        for (int i = s.length() - 1; i >= 0; --i) {
            if (s[i] == '-') continue;
            if (count == k) {
                res = '-' + res;
                count = 0;
            }
            res = toupper(s[i]) + res;
            count++;
        }
        return res;
    }
};
```
